"""HLD Patterns: Real-time Updates, Dealing with Contention, Multi-step Processes, Scaling Reads — 20 MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def realtime_updates_lesson() -> Lesson:
    return Lesson(id="hld-realtime-updates", number=109, title="Real-time Updates",
        focus=("WebSockets","SSE","long polling","pub/sub","push vs pull","event-driven"),
        overview="Real-time updates are asked about in nearly every interview. Know the protocols and when to use each.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("rt-1","What are the three main approaches for real-time updates?","medium",("real-time",),("REST, GraphQL, gRPC","Polling, long polling, and persistent connections (WebSockets/SSE)","Push, pull, hybrid","TCP, UDP, QUIC"),1,"Polling (wasteful), long polling (server holds request), WebSockets/SSE (persistent connection)."),
        quiz("rt-2","When should you use WebSockets over SSE?","hard",("real-time",),("Always","When you need bidirectional communication (chat, gaming) — SSE is server-to-client only","SSE is always better","They are identical"),1,"WebSockets: bidirectional (chat). SSE: unidirectional server→client (live scores, notifications)."),
        quiz("rt-3","What is the fan-out problem in real-time systems?","hard",("real-time",),("Too many fans","When one event must be delivered to millions of subscribers simultaneously","A caching issue","A database problem"),1,"Solutions: tiered fan-out, push for most users + pull for celebrity followers, connection pooling."),
        quiz("rt-4","How does Redis pub/sub work for real-time?","medium",("real-time",),("A database transaction","Publishers send to channels; subscribers receive messages instantly — fire-and-forget","A cache eviction","A replication mode"),1,"Redis pub/sub is lightweight but doesn't persist messages. Missed messages are gone."),
        quiz("rt-5","What is the difference between pub/sub and message queues for real-time?","hard",("real-time",),("Same thing","Pub/sub broadcasts to all subscribers; queues deliver to one consumer per message","Pub/sub is slower","Queues are real-time only"),1,"Pub/sub: one-to-many broadcast. Queue: one-to-one competing consumers."),
        quiz("rt-6","How do you handle millions of concurrent WebSocket connections?","hard",("real-time",),("One server handles all","Distribute across many servers with sticky sessions or a presence service tracking which server handles which user","Use HTTP instead","Limit to 10K connections"),1,"Use a presence service (Redis) to track user→server mapping. Route messages accordingly."),
        quiz("rt-7","What is a presence service?","medium",("real-time",),("A health check","A system tracking which users are online and which server they're connected to","A load balancer","An auth service"),1,"Presence services (Redis/ZooKeeper) maintain user→server mappings for routing real-time messages."),
        quiz("rt-8","How does Slack/Discord handle real-time message delivery?","hard",("real-time",),("HTTP polling","WebSocket connections per client, gateway servers handling connections, internal message routing via pub/sub","Email notifications","SMS"),1,"Gateway servers maintain WS connections. Internal pub/sub routes messages between gateways."),
        quiz("rt-9","What is connection multiplexing in real-time systems?","hard",("real-time",),("One connection per request","Multiple logical channels share a single physical connection (e.g., Socket.IO rooms)","A load balancing technique","A caching strategy"),1,"Multiplexing reduces connection overhead. One WS connection can subscribe to multiple topics/rooms."),
        quiz("rt-10","What is the heartbeat mechanism in WebSockets?","medium",("real-time",),("A health check endpoint","Periodic ping/pong messages to detect dead connections and keep firewalls/proxies from closing idle connections","A load balancer feature","An encryption step"),1,"Without heartbeats, dead connections go undetected, wasting server resources."),
        quiz("rt-11","How do you handle message ordering in distributed real-time systems?","hard",("real-time",),("TCP handles it","Use sequence numbers per channel/user, buffer out-of-order messages, and deliver in sequence","Messages are always ordered","Use UDP"),1,"Distributed systems can deliver messages out of order. Client-side reordering with sequence numbers fixes this."),
        quiz("rt-12","What is the difference between push and pull models for news feeds?","hard",("real-time",),("Same thing","Push: precompute feeds on post (fan-out on write). Pull: compute at read time (fan-out on read)","Push is always better","Pull doesn't use caching"),1,"Push for regular users. Pull for celebrities. Hybrid is best."),
        quiz("rt-13","What is event-driven architecture?","medium",("real-time",),("Synchronous request/response","Components communicate by producing and consuming events asynchronously via a message broker","A database architecture","A caching pattern"),1,"Event-driven decouples producers from consumers, enabling scalability and loose coupling."),
        quiz("rt-14","What is MQTT and when is it used?","hard",("real-time",),("A REST alternative","A lightweight publish-subscribe protocol designed for IoT and mobile devices with unreliable networks","A database protocol","A caching protocol"),1,"MQTT is lightweight (small header), supports QoS levels, and handles unreliable connections well."),
        quiz("rt-15","How does Firebase Realtime Database handle real-time sync?","hard",("real-time",),("HTTP polling","WebSocket connections with path-based subscriptions; server pushes only changed data (diffs)","REST API","gRPC streaming"),1,"Firebase sends only data diffs, reducing bandwidth. Clients subscribe to specific paths in the JSON tree."),
        quiz("rt-16","What is the challenge of real-time updates at scale?","hard",("real-time",),("UI design","Maintaining millions of persistent connections, efficient message routing, and handling connection churn","Database speed","API design"),1,"At scale: connection management, efficient pub/sub routing, and graceful handling of reconnections."),
        quiz("rt-17","What is the difference between at-most-once and at-least-once delivery in real-time?","hard",("real-time",),("Same thing","At-most-once may lose messages; at-least-once may deliver duplicates but never loses","At-most-once is more reliable","At-least-once loses messages"),1,"Chat apps need at-least-once + deduplication. Notifications can tolerate at-most-once."),
        quiz("rt-18","How do you implement typing indicators in a chat app?","medium",("real-time",),("Store in database","Send ephemeral WebSocket events that are NOT persisted — they're purely transient signals","HTTP polling","Push notifications"),1,"Typing indicators are fire-and-forget signals. No persistence needed — if missed, no harm done."),
        quiz("rt-19","What is the role of a message broker in real-time systems?","medium",("real-time",),("Database replacement","Decouples producers from consumers, buffers messages, and enables async processing","A load balancer","A cache"),1,"Brokers (Kafka, RabbitMQ, Redis Streams) provide reliability, ordering, and fan-out capabilities."),
        quiz("rt-20","How does gRPC server streaming work for real-time?","hard",("real-time",),("Same as WebSockets","Server sends a stream of messages over a single HTTP/2 connection; client receives them sequentially","A REST pattern","A database feature"),1,"gRPC streaming: server opens a response stream. Efficient binary serialization via Protobuf."),
    ))

def contention_lesson() -> Lesson:
    return Lesson(id="hld-contention", number=110, title="Dealing with Contention",
        focus=("optimistic locking","pessimistic locking","CAS","distributed locks","hot partitions"),
        overview="Contention is the enemy of scale. Know when to lock, when to avoid locks, and how to design around hotspots.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("cnt-1","What is optimistic concurrency control?","medium",("contention",),("Always use locks","Assume no conflict; check version at commit time and retry if conflict detected","A database index","A caching strategy"),1,"Optimistic works well with low contention. Higher throughput than pessimistic locking."),
        quiz("cnt-2","What is pessimistic locking?","medium",("contention",),("No locking","Lock the resource upfront before any operation to prevent conflicts","A read-only strategy","A caching technique"),1,"SELECT FOR UPDATE in SQL. Prevents conflicts but reduces throughput due to lock contention."),
        quiz("cnt-3","What is compare-and-swap (CAS)?","hard",("contention",),("A sorting algorithm","An atomic operation: read current value, compare with expected, swap only if match","A hashing technique","A compression method"),1,"CAS is the foundation of lock-free data structures. Redis WATCH/MULTI implements CAS semantics."),
        quiz("cnt-4","How do you handle ticket purchasing contention (Ticketmaster)?","hard",("contention",),("No locking needed","Temporary seat reservation with TTL + atomic inventory decrement (Redis DECR or DB row lock)","Queue all buyers","Let them fight"),1,"Reserve with TTL (10 min), decrement atomically, release on timeout or payment completion."),
        quiz("cnt-5","What is the hot partition problem?","hard",("contention",),("A temperature issue","One partition/shard receiving disproportionate traffic, becoming a bottleneck","A caching problem","A network issue"),1,"Solutions: add entropy to key (salting), split the hot key, or use write-behind buffering."),
        quiz("cnt-6","What is distributed locking?","hard",("contention",),("File locking","Coordinating mutual exclusion across multiple nodes using a distributed lock service","A database lock","A load balancer feature"),1,"Implemented via Redis (Redlock), ZooKeeper, or etcd. More complex and less reliable than local locks."),
        quiz("cnt-7","What is the Redlock algorithm?","hard",("contention",),("A Redis command","Martin Kleppmann's critique: acquire locks on N/2+1 independent Redis instances with a global timeout","A hash algorithm","A consensus protocol"),1,"Redlock attempts distributed locking but is controversial — clock drift and GC pauses can break safety."),
        quiz("cnt-8","What is idempotency and how does it help with contention?","hard",("contention",),("A locking strategy","Making operations safe to retry — if contention causes failure, the client retries without side effects","A caching technique","A sorting algorithm"),1,"Idempotency keys let servers detect duplicates, making retry-on-conflict safe."),
        quiz("cnt-9","How do you handle the counter problem at scale?","hard",("contention",),("Single counter","Shard the counter across N shards, increment random shard, sum all shards for total (approximate)","Use a single DB row","Lock the counter"),1,"Single counters don't scale. Sharded counters trade accuracy for throughput."),
        quiz("cnt-10","What is the leaky bucket algorithm for handling contention?","hard",("contention",),("A data structure","Requests flow in at any rate but are processed at a fixed rate — excess requests are dropped or queued","A caching strategy","A locking mechanism"),1,"Leaky bucket smooths bursty traffic. Unlike token bucket, it enforces a strict constant output rate."),
        quiz("cnt-11","How does Stripe handle payment contention?","hard",("contention",),("No special handling","Idempotency keys + optimistic locking + event sourcing ensure exactly-once payment processing","Lock the entire database","Queue all payments"),1,"Each payment has a unique idempotency key. Retries check the key and return the existing result."),
        quiz("cnt-12","What is write skew and how do you prevent it?","hard",("contention",),("A UI issue","Two transactions read overlapping data, make decisions, and write — each valid individually but together violate a constraint","A read problem","A caching issue"),1,"Example: two doctors both see 3 on-call, each decides to remove themselves, leaving 1. Fix: serializable isolation."),
        quiz("cnt-13","What is a semaphore vs a mutex?","medium",("contention",),("Same thing","Mutex allows one holder; semaphore allows N concurrent holders (counting semaphore)","Semaphore is faster","Mutex allows many holders"),1,"Use mutex for exclusive access. Use semaphore to limit concurrency (e.g., max 10 DB connections)."),
        quiz("cnt-14","How do you handle auction bid contention?","hard",("contention",),("No locking","Atomic compare-and-swap: read current highest → compare → update only if new bid is higher","Queue all bids","Lock the entire auction"),1,"CAS pattern: ensure only the highest valid bid wins without race conditions."),
        quiz("cnt-15","What is the thundering herd problem in locking?","hard",("contention",),("A noise issue","When a lock is released, all waiting threads wake up and compete for it, causing CPU spikes","A network problem","A database issue"),1,"Solution: use fair locks (FIFO queue) or exponential backoff with jitter."),
        quiz("cnt-16","What is a read-write lock?","medium",("contention",),("A database feature","Allows multiple concurrent readers OR a single writer — improves throughput for read-heavy workloads","A file lock","A network protocol"),1,"RW locks: many readers share access. Writers get exclusive access. Readers block only during writes."),
        quiz("cnt-17","How does MVCC handle contention?","hard",("contention",),("It doesn't","Each transaction sees a snapshot of the data, allowing concurrent reads/writes without blocking","A locking mechanism","A replication strategy"),1,"MVCC: readers don't block writers, writers don't block readers. Each sees a consistent snapshot."),
        quiz("cnt-18","What is exponential backoff with jitter?","medium",("contention",),("A sleep schedule","Retry with exponentially increasing delays plus random jitter to spread retries and reduce contention","A constant retry","A timeout strategy"),1,"Wait = min(cap, base × 2^attempt) + random_jitter. Prevents synchronized retry storms."),
        quiz("cnt-19","What is the inventory reservation pattern?","hard",("contention",),("Counting stock","Reserve items with a TTL during checkout; release if payment fails or times out","Lock all inventory","Pre-purchase all items"),1,"Prevents overselling while allowing concurrent checkouts. TTL-based reservations auto-expire."),
        quiz("cnt-20","What is the saga pattern for handling distributed contention?","hard",("contention",),("A long transaction","A sequence of local transactions with compensating actions — avoids distributed locks entirely","A locking protocol","A consensus algorithm"),1,"Sagas replace distributed locks with local transactions + compensations. No 2PC blocking needed."),
    ))

def multistep_lesson() -> Lesson:
    return Lesson(id="hld-multistep", number=111, title="Multi-step Processes",
        focus=("sagas","2PC","event sourcing","outbox pattern","compensating actions","workflow engines"),
        overview="Distributed transactions are inevitable. Know Sagas, 2PC, event sourcing, and when to use each.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("ms-1","What is the Saga pattern?","hard",("saga",),("A long DB transaction","A sequence of local transactions where each step has a compensating action for rollback","A type of 2PC","A caching pattern"),1,"Sagas handle distributed transactions without 2PC. Each step can be undone independently."),
        quiz("ms-2","Choreography vs orchestration sagas?","hard",("saga",),("No difference","Choreography: services react to events. Orchestration: a central coordinator directs steps","Orchestration is decentralized","Choreography uses a coordinator"),1,"Choreography is more decoupled. Orchestration is centralized and easier to reason about."),
        quiz("ms-3","What is two-phase commit (2PC)?","hard",("distributed",),("A caching technique","Prepare phase (all vote) → commit phase (all commit or all abort). Atomic but blocking","A load balancing algorithm","A database index"),1,"2PC guarantees atomicity but blocks if coordinator fails. Avoided in microservices."),
        quiz("ms-4","Why is 2PC problematic in microservices?","hard",("distributed",),("It's too simple","Blocking nature, coordinator SPOF, high latency, and tight coupling between services","It's too fast","It doesn't work"),1,"2PC blocks all participants if coordinator fails. Sagas are preferred for loose coupling."),
        quiz("ms-5","What is event sourcing?","hard",("event-sourcing",),("Logging errors","Storing all state changes as an immutable event log instead of just current state","A message queue","Database sharding"),1,"Event sourcing gives audit trails, time travel, and ability to rebuild state from events."),
        quiz("ms-6","What is the outbox pattern?","hard",("patterns",),("A logging technique","Write events to an outbox table in the same DB transaction, then publish asynchronously","An email pattern","A caching strategy"),1,"Outbox ensures atomicity between DB writes and event publishing. Avoids dual-write problems."),
        quiz("ms-7","What is a compensating transaction?","medium",("saga",),("A refund","An action that undoes the effect of a previous transaction step (e.g., cancel booking, refund payment)","A database rollback","A cache clear"),1,"In Sagas, compensations undo completed steps when a later step fails."),
        quiz("ms-8","What is the CDC (Change Data Capture) approach to multi-step?","hard",("patterns",),("Backing up data","Streaming DB changes as events via the WAL, enabling downstream systems to react asynchronously","A caching strategy","A migration tool"),1,"CDC (Debezium) turns DB changes into events without modifying application code."),
        quiz("ms-9","How do you handle partial failures in a Saga?","hard",("saga",),("Ignore them","Execute compensating transactions for completed steps in reverse order","Retry everything","Lock all services"),1,"If step 3 of 5 fails: compensate step 2, compensate step 1. Each compensation must be idempotent."),
        quiz("ms-10","What is the transactional outbox implementation?","hard",("patterns",),("A message queue","Write to outbox table in same DB transaction as business data; a poller/CDC reads outbox and publishes events","A cache pattern","A file system"),1,"Guarantees at-least-once event publishing without distributed transactions."),
        quiz("ms-11","What are the challenges of event sourcing?","hard",("event-sourcing",),("It's too simple","Schema evolution, event versioning, replay performance, and eventual consistency of read models","No challenges","Only works for small data"),1,"Event stores grow forever. Snapshots help. Event schema changes require migration strategies."),
        quiz("ms-12","What is a process manager in orchestration sagas?","hard",("saga",),("A Unix process","A stateful coordinator that tracks saga progress, sends commands, and handles responses/timeouts","A load balancer","A database"),1,"The process manager maintains saga state and drives the workflow forward."),
        quiz("ms-13","What is idempotency's role in multi-step processes?","hard",("saga",),("Not relevant","Every step must be idempotent so that retries after partial failures don't cause side effects","A performance optimization","A UI concern"),1,"Without idempotency, retrying a failed saga step could duplicate charges, bookings, etc."),
        quiz("ms-14","What is the dead letter queue in multi-step processes?","medium",("patterns",),("A deleted queue","Where messages that fail processing after max retries are sent for investigation","A logging mechanism","A backup queue"),1,"DLQs prevent poison messages from blocking the pipeline."),
        quiz("ms-15","How do you ensure exactly-once processing in sagas?","hard",("saga",),("Impossible","At-least-once delivery + idempotent consumers = effectively-once processing","Use 2PC","Use TCP"),1,"True exactly-once is nearly impossible. Idempotent handlers make duplicates harmless."),
        quiz("ms-16","What is the difference between choreography and orchestration in reliability?","hard",("saga",),("Choreography is more reliable","Choreography is harder to debug (implicit flow); orchestration provides clear visibility and error handling","Orchestration is unreliable","No difference"),1,"Choreography: implicit flow in event subscriptions. Orchestration: explicit, traceable state machine."),
        quiz("ms-17","What is a workflow engine (e.g., Temporal, Cadence)?","hard",("patterns",),("A CI/CD tool","A platform for defining, executing, and recovering durable multi-step workflows with built-in retry/state management","A load balancer","A message queue"),1,"Temporal/Cadence handle timeouts, retries, compensations, and state persistence automatically."),
        quiz("ms-18","What is the try-confirm-cancel (TCC) pattern?","hard",("patterns",),("Same as 2PC","A reservation pattern: Try (reserve), Confirm (commit), or Cancel (release) — each service manages its own resources","A caching pattern","A locking mechanism"),1,"TCC is like Saga but with explicit reservation. Each service locks resources during Try phase."),
        quiz("ms-19","How does event sourcing relate to CQRS?","hard",("event-sourcing",),("No relation","Events drive the write model; read models are projections of events optimized for queries — naturally complementary","CQRS replaces event sourcing","They are identical"),1,"Event sourcing provides the event log. CQRS projects it into read-optimized materialized views."),
        quiz("ms-20","What is the at-least-once delivery guarantee and why is it the practical choice?","hard",("patterns",),("Exactly-once is easier","At-most-once may lose messages; exactly-once is nearly impossible; at-least-once + idempotent consumers is practical","At-most-once is preferred","All guarantees are equal"),1,"At-least-once is achievable with acks/retries. Combined with idempotent processing, it's effectively-once."),
    ))

def scaling_reads_lesson() -> Lesson:
    return Lesson(id="hld-scaling-reads", number=112, title="Scaling Reads",
        focus=("read replicas","caching","CQRS","CDN","denormalization","materialized views"),
        overview="Most applications are read-heavy. Know the full toolkit for scaling reads efficiently.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("sr-1","What is the most common approach to scaling reads?","easy",("scaling-reads",),("Faster CPU","Add read replicas — write to primary, read from replicas","Bigger database","More indexes"),1,"Read replicas distribute read load. Works well for read-heavy workloads with tolerable replication lag."),
        quiz("sr-2","What is CQRS?","hard",("scaling-reads",),("A caching strategy","Command Query Responsibility Segregation — separate read and write models optimized independently","A database type","A load balancing technique"),1,"CQRS: write model can be normalized for consistency; read model can be denormalized for speed."),
        quiz("sr-3","How does denormalization help read performance?","medium",("scaling-reads",),("It doesn't","Pre-joins data into a single read-optimized structure, eliminating JOIN queries at read time","Reduces storage","Improves write speed"),1,"Denormalization trades write complexity and storage for dramatically faster reads."),
        quiz("sr-4","What is a materialized view?","medium",("scaling-reads",),("A regular view","A precomputed query result stored as a table, updated periodically or on write","An index","A cache"),1,"Materialized views: precomputed aggregations/JOINs. Great for dashboards and analytics."),
        quiz("sr-5","What is the replication lag problem?","hard",("scaling-reads",),("No problem","Time delay between a write on the primary and when it appears on replicas, causing stale reads","A network issue","A caching problem"),1,"Solution: read-your-own-writes by routing the writing user to the primary for subsequent reads."),
        quiz("sr-6","When is caching better than read replicas?","medium",("scaling-reads",),("Always","When you need sub-millisecond reads, data access patterns follow 80/20, and slight staleness is OK","Never","When data changes frequently"),1,"Cache: μs latency, handles hot data well. Replicas: ms latency, serve all data."),
        quiz("sr-7","What is the query result cache pattern?","medium",("scaling-reads",),("Database cache","Cache the full result of expensive queries using the query+params as the cache key","An index","A view"),1,"Cache key = hash(query + params). Invalidate when underlying data changes."),
        quiz("sr-8","How does CDN help scale reads?","easy",("scaling-reads",),("Database scaling","Caches static content at edge locations near users, reducing origin server load","API routing","Database replication"),1,"CDNs serve images, CSS, JS, and even API responses from edge — reducing latency and origin load."),
        quiz("sr-9","What is read-through caching in the context of scaling reads?","medium",("scaling-reads",),("Same as cache-aside","The cache transparently fetches from DB on miss — application only talks to the cache","A write strategy","A replication mode"),1,"Read-through simplifies application code — the cache handles the DB interaction."),
        quiz("sr-10","What is the fan-out on read approach?","hard",("scaling-reads",),("Pre-computing feeds","Computing the result at read time by querying and aggregating from multiple sources","A caching strategy","A write approach"),1,"Fan-out on read: cheaper writes but more expensive reads. Good for data that's written by celebrities."),
        quiz("sr-11","How do you handle search scaling for reads?","hard",("scaling-reads",),("Use the main database","Use a dedicated search engine (Elasticsearch) as a denormalized read model","Use more indexes","Increase CPU"),1,"Elasticsearch as a read-optimized projection: sync data via CDC, serve search/filter queries."),
        quiz("sr-12","What is pre-computation for scaling reads?","medium",("scaling-reads",),("Real-time calculation","Compute expensive results offline and store them for fast retrieval (e.g., recommendation scores, leaderboards)","A caching issue","A network optimization"),1,"Pre-compute: leaderboards, recommendation scores, trending topics. Serve from cache/fast store."),
        quiz("sr-13","How do read replicas handle failover?","hard",("scaling-reads",),("They don't","Promote a replica to primary when the primary fails; other replicas switch to the new primary","Auto-restart the primary","Use the cache instead"),1,"Failover promotes a replica. Some systems (RDS Multi-AZ) handle this automatically."),
        quiz("sr-14","What is the N+1 read problem and how does it affect scaling?","hard",("scaling-reads",),("A network issue","Fetching a list (1 query) then N individual queries for related data — turns 1 query into N+1","A caching problem","A replication lag"),1,"N+1 multiplies database load. Fix with JOINs, batch fetching, or DataLoader pattern."),
        quiz("sr-15","What is edge computing for read scaling?","hard",("scaling-reads",),("Desktop computing","Processing and serving data at edge locations closer to users, reducing round-trip latency","A database feature","A caching protocol"),1,"Edge computing (Cloudflare Workers, Lambda@Edge): run logic at CDN edge, not just cache content."),
        quiz("sr-16","How do you scale read-heavy time-series queries?","hard",("scaling-reads",),("Single database","Use time-based partitioning + downsampling + tiered storage (hot/warm/cold)","More indexes","Bigger machine"),1,"Recent data in fast store (SSD), older data downsampled and moved to cheaper storage."),
        quiz("sr-17","What is data locality optimization for reads?","medium",("scaling-reads",),("Storing all data together","Storing related data that's frequently accessed together physically close (same partition, same node)","A network optimization","A caching strategy"),1,"Co-locating related data reduces cross-partition reads and improves cache utilization."),
        quiz("sr-18","When should you NOT add read replicas?","medium",("scaling-reads",),("Never","When write-heavy workload means replicas can't keep up, or consistency requirements don't tolerate lag","When reads are high","When using NoSQL"),1,"Write-heavy workloads: replicas lag behind, serving stale data. Consider caching or sharding instead."),
        quiz("sr-19","What is a query plan cache?","hard",("scaling-reads",),("A result cache","Database caches parsed/optimized query plans to avoid re-planning identical queries","A disk cache","An index cache"),1,"Plan caching (prepared statements) eliminates query parsing overhead for repeated queries."),
        quiz("sr-20","How does pagination help scale reads?","easy",("scaling-reads",),("It doesn't","Breaks large result sets into pages, reducing memory usage and response size per request","Speeds up writes","Improves consistency"),1,"Without pagination, returning 1M rows crashes clients and overwhelms servers."),
    ))
